#nullable enable // autogenerated

using MVZ2.GameContent.Maps;
using MVZ2.Vanilla.Properties;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Maps;
using PVZEngine;

namespace MVZ2.GameContent.IZombie
{
    [AutoMapElementBehaviourDefinition(VanillaMapElementBehaviourNames.pin)]
    public class PinMapElement : MapElementBehaviourDefinition
    {
        public PinMapElement(string nsp, string name) : base(nsp, name)
        {
        }
        public override void OnClick(IMapElement element)
        {
            var map = element.Map;
            if (IsToStore(element))
            {
                var mapID = map.GetMapID();
                Global.Scene.GotoStore(() => Global.Scene.GotoMap(mapID), true);
                return;
            }
            var targetMap = GetTargetMapID(element);
            if (NamespaceID.IsValid(targetMap))
            {
                map.ChangeMap(targetMap);
            }
        }
        public static bool IsToStore(IMapElement element) => element.GetProperty<bool>(PROP_TO_STORE);
        public static void SetToStore(IMapElement element, bool value) => element.SetProperty(PROP_TO_STORE, value);
        public static NamespaceID? GetTargetMapID(IMapElement element) => element.GetProperty<NamespaceID>(PROP_TARGET_MAP_ID);
        public static void SetTargetMapID(IMapElement element, NamespaceID? value) => element.SetProperty(PROP_TARGET_MAP_ID, value);
        public static readonly VanillaEntityPropertyMeta<bool> PROP_TO_STORE = new VanillaEntityPropertyMeta<bool>("to_store");
        public static readonly VanillaEntityPropertyMeta<NamespaceID> PROP_TARGET_MAP_ID = new VanillaEntityPropertyMeta<NamespaceID>("target_map_id");
    }
}
